812:                                                 new CheckpointException(
813:                                                         CheckpointFailureReason
814:                                                                 .TRIGGER_CHECKPOINT_FAILURE,
815:                                                         failure);
816:                                     }
817:                                     timer.execute(
818:                                             () -> {
