825:                             });
826: 
827:             // It is possible that the tasks has finished
828:             // checkpointing at this point.
829:             // So we need to complete this pending checkpoint.
830:             if (maybeCompleteCheckpoint(checkpoint)) {
831:                 onTriggerSuccess();
832:             }
