213:     @Override
214:     public void processBarrier(
215:             CheckpointBarrier barrier, InputChannelInfo channelInfo, boolean isRpcTriggered)
216:             throws IOException {
217:         long barrierId = barrier.getId();
218:         LOG.debug("{}: Received barrier from channel {} @ {}.", taskName, channelInfo, barrierId);
219: 
220:         if (currentCheckpointId > barrierId
221:                 || (currentCheckpointId == barrierId && !isCheckpointPending())) {
222:             if (!barrier.getCheckpointOptions().isUnalignedCheckpoint()) {
223:                 inputs[channelInfo.getGateIdx()].resumeConsumption(channelInfo);
224:             }
225:             return;
226:         }
227: 
228:         checkNewCheckpoint(barrier);
229:         checkState(currentCheckpointId == barrierId);
230: 
231:         markCheckpointAlignedAndTransformState(
232:                 channelInfo,
233:                 barrier,
234:                 state -> state.barrierReceived(context, channelInfo, barrier, !isRpcTriggered));
235:     }
