170:     @Override
171:     public void processCancellationBarrier(
172:             CancelCheckpointMarker cancelBarrier, InputChannelInfo channelInfo) throws IOException {
173:         final long checkpointId = cancelBarrier.getCheckpointId();
174: 
175:         if (LOG.isDebugEnabled()) {
176:             LOG.debug("Received cancellation barrier for checkpoint {}", checkpointId);
177:         }
178: 
179:         // fast path for single channel trackers. We only go with the fast path
180:         // for new checkpoints, otherwise we might met with the case that
181:         // 1. Received barrier from channel 0 (2 in total) and start a new checkpoint.
182:         // 2. Received EndOfPartition from channel 0.
183:         // 3. Received cancellation barrier from channel 1.
184:         // In this case we should cleanup the existing pending checkpoint.
185:         if (cancelBarrier.getCheckpointId() > latestPendingCheckpointID && numOpenChannels == 1) {
186:             resetAlignment();
187:             notifyAbortOnCancellationBarrier(checkpointId);
188:             return;
189:         }
190: 
191:         // -- general path for multiple input channels --
192: 
193:         // find the checkpoint barrier in the queue of pending barriers
194:         // while doing this we "abort" all checkpoints before that one
195:         CheckpointBarrierCount cbc;
196:         while ((cbc = pendingCheckpoints.peekFirst()) != null
197:                 && cbc.checkpointId() < checkpointId) {
198:             pendingCheckpoints.removeFirst();
199: 
200:             if (cbc.markAborted()) {
201:                 // abort the subsumed checkpoints if not already done
202:                 notifyAbortOnCancellationBarrier(cbc.checkpointId());
203:             }
204:         }
205: 
206:         if (cbc != null && cbc.checkpointId() == checkpointId) {
207:             // make sure the checkpoint is remembered as aborted
208:             if (cbc.markAborted()) {
209:                 // this was the first time the checkpoint was aborted - notify
210:                 notifyAbortOnCancellationBarrier(checkpointId);
211:             }
212: 
213:             // we still count the barriers to be able to remove the entry once all barriers have
214:             // been seen
215:             if (cbc.markChannelAligned(channelInfo) == cbc.getTargetChannelCount()) {
216:                 // we can remove this entry
217:                 pendingCheckpoints.removeFirst();
218:             }
219:         } else if (checkpointId > latestPendingCheckpointID) {
220:             notifyAbortOnCancellationBarrier(checkpointId);
221: 
222:             latestPendingCheckpointID = checkpointId;
223: 
224:             CheckpointBarrierCount abortedMarker =
225:                     new CheckpointBarrierCount(
226:                             cancelBarrier.getCheckpointId(), channelInfo, numOpenChannels);
227:             abortedMarker.markAborted();
228:             pendingCheckpoints.addFirst(abortedMarker);
229: 
230:             // we have removed all other pending checkpoint barrier counts --> no need to check that
231:             // we don't exceed the maximum checkpoints to track
232:         } else {
233:             // trailing cancellation barrier which was already cancelled
234:         }
235:     }
