237:     @Override
238:     public void processEndOfPartition(InputChannelInfo channelInfo) throws IOException {
239:         numOpenChannels--;
240: 
241:         if (!isCheckpointAfterTasksFinishedEnabled()) {
242:             while (!pendingCheckpoints.isEmpty()) {
243:                 CheckpointBarrierCount barrierCount = pendingCheckpoints.removeFirst();
244:                 if (barrierCount.markAborted()) {
245:                     notifyAbort(
246:                             barrierCount.checkpointId(),
247:                             new CheckpointException(
248:                                     CheckpointFailureReason
249:                                             .CHECKPOINT_DECLINED_INPUT_END_OF_STREAM));
250:                 }
251:             }
252:             resetAlignment();
253:         } else {
254:             checkAlignmentOnEndOfPartitionIfEnabled(channelInfo);
255:         }
256:     }
257: 
258:     private void checkAlignmentOnEndOfPartitionIfEnabled(InputChannelInfo channelInfo)
259:             throws IOException {
260:         // Finds the latest pending checkpoints that only waits for this channel.
261:         CheckpointBarrierCount barrierCount = null;
262:         int pos = pendingCheckpoints.size();
263: 
264:         Iterator<CheckpointBarrierCount> reverseCheckpointIterator =
265:                 pendingCheckpoints.descendingIterator();
266:         while (reverseCheckpointIterator.hasNext()) {
267:             CheckpointBarrierCount next = reverseCheckpointIterator.next();
268:             pos--;
269: 
270:             if (next.markChannelAligned(channelInfo) == next.getTargetChannelCount()) {
271:                 barrierCount = next;
272:                 break;
273:             }
274:         }
275: 
276:         if (barrierCount != null) {
277:             for (int i = 0; i <= pos; i++) {
278:                 pendingCheckpoints.pollFirst();
279:             }
280: 
281:             if (!barrierCount.isAborted()) {
282:                 triggerCheckpointOnAligned(barrierCount);
283:             }
284:         }
285:     }
286: 
287:     private void triggerCheckpointOnAligned(CheckpointBarrierCount barrierCount)
288:             throws IOException {
289:         if (LOG.isDebugEnabled()) {
290:             LOG.debug(
291:                     "All the channels are aligned for checkpoint {}", barrierCount.checkpointId());
292:         }
293: 
294:         // Only one calculation of the alignment time at once is supported right now.
295:         if (barrierCount.checkpointId == latestPendingCheckpointID) {
296:             markAlignmentEnd();
297:         }
298:         checkState(
299:                 barrierCount.getPendingCheckpoint() != null,
300:                 "Pending checkpoint barrier must" + "exists for non-aborted checkpoints.");
301:         notifyCheckpoint(barrierCount.getPendingCheckpoint());
302:     }
