304:     public long getLatestCheckpointId() {
305:         return pendingCheckpoints.isEmpty() ? -1 : pendingCheckpoints.peekLast().checkpointId();
306:     }
307: 
308:     public boolean isCheckpointPending() {
309:         return !pendingCheckpoints.isEmpty();
310:     }
