381:             return firstAbort;
382:         }
383: 
384:         @Override
385:         public String toString() {
386:             return isAborted()
387:                     ? String.format("checkpointID=%d - ABORTED", checkpointId)
388:                     : String.format(
389:                             "checkpointID=%d, count=%d, targetChannelCount=%d",
390:                             checkpointId, alignedChannels.size(), targetChannelCount);
391:         }
