19: package org.apache.flink.streaming.runtime.io.checkpointing;
20: 
21: import org.apache.flink.annotation.VisibleForTesting;
22: import org.apache.flink.runtime.checkpoint.CheckpointException;
23: import org.apache.flink.runtime.checkpoint.CheckpointFailureReason;
24: import org.apache.flink.runtime.checkpoint.CheckpointMetaData;
25: import org.apache.flink.runtime.checkpoint.CheckpointMetricsBuilder;
26: import org.apache.flink.runtime.checkpoint.channel.InputChannelInfo;
27: import org.apache.flink.runtime.io.network.api.CancelCheckpointMarker;
28: import org.apache.flink.runtime.io.network.api.CheckpointBarrier;
29: import org.apache.flink.runtime.jobgraph.tasks.CheckpointableTask;
